import axios from "axios";
import { useEffect, useState } from "react";
import {
  Link,
  useLocation,
  useNavigate,
} from "react-router-dom";
import { useCart } from "./CartContext";
import Select from "react-select";
import LocationSelect from "./LocationSelect";
import hashids from "../utils/hashids";

const AllHealthPackages = () => {
  const [activeButton, setActiveButton] = useState("grid-view");
  const [filter, setFilter] = useState(false);
  const [activeTab, setActiveTab] = useState("packages");
  const [services, setServices] = useState([]);
  const [packages, setPackages] = useState([]);
  const [query, setQuery] = useState("");
  const [address, setAddress] = useState("");
  const [centreType, setCentreType] = useState("");
  const [healthInsurance, setHealthInsurance] = useState(false);
  const [cashless, setCashless] = useState(false);
  const [loading, setLoading] = useState(false);
  const [places, setPlaces] = useState([]);
  const [selectedLocality, setSelectedLocality] = useState("");

  const [sortPrice, setSortPrice] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("");
  const [selectedService, setSelectedService] = useState("");
  const [filterByLocation, setFilterByLocation] = useState("");

  // Pagination State - Updated for server-side
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalPackages, setTotalPackages] = useState(0);
  const packagesPerPage = 9;

  // Current packages for display (server already paginates)
  const currentPackages = packages;

  const clearAllFilters = () => {
    setSelectedService("");
    setSelectedCategory("");
    setSortPrice("");
    setCentreType("");
    setQuery("");
    setFilterByLocation(null);
    setSelectedLocality("");
    setCurrentPage(1);
    fetchPackages(1);
  };

  const handlePageChange = (pageNumber) => {
    setCurrentPage(pageNumber);
    
    // Fetch data for the new page based on current filter state
    if (
      query.trim() === "" &&
      address.trim() === "" &&
      centreType.trim() === "" &&
      !healthInsurance &&
      !cashless &&
      !sortPrice &&
      !selectedCategory &&
      !selectedService &&
      !filterByLocation &&
      !selectedLocality
    ) {
      fetchPackages(pageNumber);
    } else {
      handleSearch(pageNumber);
    }
  };

  const handlePageChangeWithScroll = (page) => {
    handlePageChange(page);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const renderPagination = () => {
    const pages = [];
    const maxVisible = 4;
    let startPage = Math.max(1, currentPage - Math.floor(maxVisible / 2));
    let endPage = startPage + maxVisible - 1;

    if (endPage > totalPages) {
      endPage = totalPages;
      startPage = Math.max(1, endPage - maxVisible + 1);
    }

    //first button
    pages.push(
      <li
        key="first"
        className={`page-item ${currentPage === 1 ? " disabled" : ""}`}
      >
        <button
          className="page-link"
          onClick={() => currentPage !== 1 && handlePageChangeWithScroll(1)}
        >
          First
        </button>
      </li>
    );

    // Prev Button
    pages.push(
      <li
        key="prev"
        className={`page-item ${currentPage === 1 ? "disabled" : ""}`}
      >
        <button
          className="page-link"
          onClick={() => currentPage > 1 && handlePageChangeWithScroll(currentPage - 1)}
        >
          Prev
        </button>
      </li>
    );

    // Page Numbers
    for (let i = startPage; i <= endPage; i++) {
      pages.push(
        <li
          key={i}
          className={`page-item ${currentPage === i ? "active" : ""}`}
        >
          <button className="page-link" onClick={() => handlePageChangeWithScroll(i)}>
            {i}
          </button>
        </li>
      );
    }

    // Next Button
    pages.push(
      <li
        key="next"
        className={`page-item ${currentPage === totalPages ? "disabled" : ""}`}
      >
        <button
          className="page-link"
          onClick={() =>
            currentPage < totalPages && handlePageChangeWithScroll(currentPage + 1)
          }
        >
          Next
        </button>
      </li>
    );

    pages.push(
      <li
        key="last"
        className={`page-item ${currentPage === totalPages ? "disabled" : ""}`}
      >
        <button
          className="page-link"
          onClick={() => handlePageChangeWithScroll(totalPages)}
        >
          Last
        </button>
      </li>
    );

    return pages;
  };

  const { addToCart } = useCart();
  const navigate = useNavigate();

  const handleBookNow = async (serviceId, fromPage) => {
    try {
      const response = await axios.get(
        `${process.env.REACT_APP_BACKEND_URL}/api/centreService/single/${serviceId}`
      );
      const selectedService = response.data;
      addToCart(selectedService);
      navigate("/cart", { state: { from: fromPage } });
    } catch (error) {
      console.error("Error adding to cart", error);
    }
  };

  const { cartItems } = useCart();

  const isPackageInCart = (pkgId) => {
    return cartItems.some(
      (item) => item.type === "package" && item._id === pkgId
    );
  };

  const handleBookNowPackage = async (packageId, fromPage) => {
    if (isPackageInCart(packageId)) {
      navigate("/cart", { state: { from: fromPage } });
      return;
    }

    try {
      const response = await axios.get(
        `${process.env.REACT_APP_BACKEND_URL}/api/packages/single/${packageId}`
      );
      const selectedPackage = {
        ...response.data,
        type: "package",
      };

      addToCart(selectedPackage);
      navigate("/cart", { state: { from: fromPage } });
    } catch (error) {
      console.error("Error adding package to cart", error);
    }
  };

  const fetchLocalityByDistrict = async (district) => {
    try {
      const res = await axios.get(
        `${process.env.REACT_APP_BACKEND_URL}/api/places/by-district`,
        {
          params: { district: district }
        }
      );
      setPlaces(res.data.offices || []);
    } catch (error) {
      console.error("Failed to get Locality by district", error);
      setPlaces([]);
    }
  };

 const fetchPackages = async (page = 1) => {
  try {
    setLoading(true);
    const res = await axios.get(
      `${process.env.REACT_APP_BACKEND_URL}/api/packages/`,
      {
        params: {
          page: page,
          limit: packagesPerPage
        }
      }
    );
    
    
    // Handle different response structures
    if (res.data.packages) {
      // Paginated response
      setPackages(res.data.packages);
      setCurrentPage(res.data.currentPage || page);
      setTotalPages(res.data.totalPages || 1);
      setTotalPackages(res.data.totalPackages || res.data.packages.length);
    } else if (Array.isArray(res.data)) {
      // Non-paginated response - do client-side pagination
      setPackages(res.data);
      setTotalPages(Math.ceil(res.data.length / packagesPerPage));
      setTotalPackages(res.data.length);
      setCurrentPage(page);
    }
    
  } catch (error) {
    console.error("Error fetching packages", error.message);
    setPackages([]);
    setTotalPages(1);
  } finally {
    setLoading(false);
  }
};

  useEffect(() => {
    if (filterByLocation) {
      fetchLocalityByDistrict(filterByLocation);
    } else {
      setPlaces([]);
    }
  }, [filterByLocation]);

  const handleTabChange = (tabName) => {
    setActiveTab(tabName);
    setCurrentPage(1);
  };

  const handleClick = (buttonName) => {
    setActiveButton(buttonName);
  };

  const handleFilter = () => {
    setFilter(!filter);
  };

  const [isSearching, setIsSearching] = useState(false);
  const [noServicesMsg, setNoServicesMsg] = useState("");
  const [noPackagesMsg, setNoPackagesMsg] = useState("");

const handleSearch = async (page = 1) => {
  try {
    setLoading(true);
    
    // Debug log to see what params are being sent
  
    
    const res = await axios.get(
      `${process.env.REACT_APP_BACKEND_URL}/api/centres/searchService&Package`,
      {
        params: {
          name: query,
          address,
          centreType,
          healthInsurance: healthInsurance ? "true" : undefined,
          cashless: cashless ? "true" : undefined,
          sortByPrice: sortPrice,
          filterByLocation,
          filterByPlace: selectedLocality,
          page: page,
          limit: packagesPerPage
        },
      }
    );

    // Debug log to see what the backend returns

    setServices(res.data.services || []);
    setPackages(res.data.packages || []);
    
    // FIXED: Check for totalPackagePages instead of totalPages
    if (res.data.totalPackagePages !== undefined) {
      setTotalPages(res.data.totalPackagePages);
      setTotalPackages(res.data.totalPackages || 0);
      setCurrentPage(res.data.currentPage || page);
    } 
    // Also check for totalPages as fallback
    else if (res.data.totalPages !== undefined) {
      setTotalPages(res.data.totalPages);
      setTotalPackages(res.data.totalPackages || 0);
      setCurrentPage(res.data.currentPage || page);
    } else {
      // If backend doesn't return pagination info, calculate from array length
      const packagesLength = res.data.packages?.length || 0;
      setTotalPages(Math.ceil(packagesLength / packagesPerPage) || 1);
      setTotalPackages(packagesLength);
      setCurrentPage(page);
    }

    // Set messages if empty
    setNoServicesMsg(
      res.data.services?.length === 0 ? "No services found." : ""
    );
    setNoPackagesMsg(
      res.data.packages?.length === 0 ? "No packages found." : ""
    );
  } catch (err) {
    console.error("Search failed", err);
    setServices([]);
    setPackages([]);
    setNoServicesMsg("No services found.");
    setNoPackagesMsg("No packages found.");
    setTotalPages(1);
    setTotalPackages(0);
  } finally {
    setLoading(false);
  }
};

  const [categories, setCategories] = useState([]);

  useEffect(() => {
    axios
      .get(
        `${process.env.REACT_APP_BACKEND_URL}/api/category/getCategoriesAndCount`
      )
      .then((res) => {
        setCategories(res.data);
      })
      .catch((err) => {
        console.error("Error fetching categories", err);
      });
  }, []);

  const [activeCategory, setActiveCategory] = useState();
  const location = useLocation();

  const getCategoryFromUrl = () => {
    const params = new URLSearchParams(location.search);
    return params.get("category") || "AllCategories";
  };

  const fetchServicesByCategory = async (category) => {
    try {
      const res = await axios.get(
        `${process.env.REACT_APP_BACKEND_URL}/api/centreService/by-category/${category}`
      );
      setServices(res.data);
    } catch (err) {
      console.error("Error fetching services:", err);
    }
  };

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const categoryFromUrl = params.get("category");

    if (categoryFromUrl) {
      setActiveCategory(categoryFromUrl.toUpperCase());
      fetchServicesByCategory(categoryFromUrl);
    } else {
      setActiveCategory("ALL");
    }

    fetchPackages(1);
  }, [location.search]);

  const [getAllcategories, setGetAllCategories] = useState([]);
  const [getAllservices, setGetAllServices] = useState([]);

  useEffect(() => {
    const fetchCategories = async () => {
      try {
        const res = await axios.get(
          `${process.env.REACT_APP_BACKEND_URL}/api/category/getAllCategories`
        );
        setGetAllCategories(res.data);
      } catch (error) {
        console.error("Error fetching categories:", error);
      }
    };
    fetchCategories();
  }, []);

  const handleCategoryChange = async (e) => {
    const selectedCategoryId = e.target.value;
    setSelectedCategory(selectedCategoryId);
    setSelectedService("");

    if (selectedCategoryId) {
      try {
        const response = await axios.get(
          `${process.env.REACT_APP_BACKEND_URL}/api/categoryService/${selectedCategoryId}`
        );
        const servicesArray = response.data?.services || [];
        setGetAllServices(servicesArray);
      } catch (err) {
        console.error("Error fetching services:", err);
      }
    } else {
      fetchAllServices();
    }
  };

  const fetchAllServices = async () => {
    try {
      const response = await axios.get(
        `${process.env.REACT_APP_BACKEND_URL}/api/categoryService/getAllServices`
      );
      setGetAllServices(response.data.services);
    } catch (err) {
      console.error("Error fetching all services:", err);
    }
  };

  useEffect(() => {
    fetchAllServices();
  }, []);

  useEffect(() => {
    const delayDebounce = setTimeout(() => {
      if (
        query.trim() === "" &&
        address.trim() === "" &&
        centreType.trim() === "" &&
        !healthInsurance &&
        !cashless &&
        !sortPrice &&
        !selectedCategory &&
        !selectedService &&
        !filterByLocation && 
        !selectedLocality
      ) {
        if (activeCategory && activeCategory !== "ALL") {
          fetchServicesByCategory(activeCategory);
        }
        fetchPackages(1);
      } else {
        setActiveCategory("ALL");
        handleSearch(1);
      }
    }, 500);

    return () => clearTimeout(delayDebounce);
  }, [
    query,
    address,
    centreType,
    healthInsurance,
    cashless,
    sortPrice,
    selectedCategory,
    selectedService,
    activeCategory,
    filterByLocation,
    selectedLocality,
  ]);

  const handleCategoryClick = (category) => {
    setActiveCategory(category);

    if (category === "ALL") {
      // fetchServices();
    } else {
      fetchServicesByCategory(category);
    }

    setQuery("");
    setAddress("");
    setCentreType("");
    setHealthInsurance(false);
    setCashless(false);
    setSortPrice("");
    setSelectedCategory("");
  };

  const toTitleCase = (str) => {
    if (!str) return "";
    return str
      .toLowerCase()
      .split(" ")
      .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
      .join(" ");
  };

  const tabLocation = useLocation();
  useEffect(() => {
    if (tabLocation.state?.tab) setActiveTab(tabLocation.state?.tab);
  }, [tabLocation.state]);

  const [centerStats, setCenterStats] = useState([]);

  useEffect(() => {
    const fetchCenterStats = async () => {
      try {
        const res = await axios.get(
          `${process.env.REACT_APP_BACKEND_URL}/api/centres/centreTypeStats`
        );
        setCenterStats(res.data);
      } catch (error) {
        console.error("Failed to get center stats", error);
      }
    };
    fetchCenterStats();
  }, []);

  useEffect(() => {
    setCurrentPage(1);
  }, [
    query,
    address,
    centreType,
    healthInsurance,
    cashless,
    sortPrice,
    selectedCategory,
    selectedService,
    activeCategory,
    filterByLocation,
    selectedLocality,
  ]);

  const createSlug = (text) => {
    if (!text) return '';
    return text
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-') 
      .replace(/^-|-$/g, ''); 
  };

  // Safe encode function for hashids
  const safeEncodeId = (id) => {
    if (!id) return '';
    try {
      return hashids.encodeHex(id.toString());
    } catch (error) {
      console.error("Error encoding ID:", error);
      return '';
    }
  };

  return (
    <section
      className={`all-product padding-y-120 ${
        activeButton === "list-view" ? "list-view" : ""
      }`}
      style={{ marginTop: "-30px" }}
    >
      <div className="container container-two">
        <div className="row">
          <div className="col-lg-12">
            <div className="filter-tab d-flex justify-content-between align-items-center flex-wrap gap-3">
              <form
                onSubmit={(e) => e.preventDefault()}
                className="search-box d-flex align-items-center"
                style={{ width: "410px" }}
              >
                <input
                  type="text"
                  className="common-input common-input--lg pill shadow-sm boder-2"
                  placeholder="Search packages . . ."
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  style={{
                    borderTopRightRadius: "0px",
                    borderBottomRightRadius: "0px",
                  }}
                />
                <button
                  type="button"
                  style={{
                    backgroundColor: "#000424",
                    height: "47px",
                    border: "none",
                    borderRadius: "0 999px 999px 0",
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    padding: "0 16px",
                    marginLeft: "-10px",
                    cursor: "pointer",
                  }}
                  onClick={() => handleSearch(1)}
                >
                  <img
                    src="assets/images/icons/search.svg"
                    alt="Search"
                    style={{ width: "20px", height: "20px" }}
                  />
                </button>
              </form>
            </div>

            <form action="#" className="filter-form pb-4 d-block">
              <div className="row gy-3">
                <div className="col-sm-4 col-xs-6">
                  <div className="flx-between gap-1">
                    <label htmlFor="sortPrice" className="form-label font-16">
                      Sort by Price
                    </label>
                  </div>

                  <div className="position-relative">
                    <select
                      id="sortPrice"
                      className="common-input border-gray-five"
                      value={sortPrice}
                      onChange={(e) => setSortPrice(e.target.value)}
                    >
                      <option value="">Select</option>
                      <option value="asc">Lowest to Highest</option>
                      <option value="desc">Highest to Lowest</option>
                    </select>
                  </div>
                </div>

                <LocationSelect
                  value={filterByLocation}
                  onChange={setFilterByLocation}
                  colClass="col-sm-4"
                />

                <div className="col-sm-4 col-xs-6">
                  <div className="flx-between gap-1">
                    <label htmlFor="sortLocality" className="form-label font-16">
                      Sort by Locality
                    </label>
                  </div>
                  <div className="position-relative">
                    <Select
                      options={
                        places.length > 0
                          ? places.map((place) => ({
                              value: place.officename,
                              label: place.officename,
                            }))
                          : [
                              {
                                value: "",
                                label: "No Places available",
                                isDisabled: true,
                              },
                            ]
                      }
                      value={
                        selectedLocality
                          ? { value: selectedLocality, label: selectedLocality }
                          : null
                      }
                      onChange={(selectedOption) =>
                        setSelectedLocality(selectedOption?.value || "")
                      }
                      placeholder={
                        places.length > 0
                          ? "Select a locality"
                          : "No Locality"
                      }
                      isClearable={places.length > 0}
                      isDisabled={places.length === 0}
                      menuPortalTarget={document.body}
                      styles={{
                        control: (base, state) => ({
                          ...base,
                          border: "1px solid #dcdcdc",
                          borderRadius: "4px",
                          minHeight: "58px",
                          boxShadow: "none",
                          "&:hover": { borderColor: "#dcdcdc" },
                          backgroundColor: state.isDisabled
                            ? "#f8f9fa"
                            : "#fff",
                        }),
                        valueContainer: (base) => ({
                          ...base,
                          padding: "0 8px",
                        }),
                        placeholder: (base) => ({
                          ...base,
                          color:
                            places.length === 0
                              ? "#6c757d"
                              : "#6c757d !important",
                          fontSize: "16px",
                          fontWeight: "400",
                          opacity: 1,
                        }),
                        menuPortal: (base) => ({ ...base, zIndex: 9999 }),
                        menuList: (base) => ({
                          ...base,
                          maxHeight: "250px",
                          overflowY: "auto",
                        }),
                        indicatorSeparator: () => ({ display: "none" }),
                        option: (base, state) => ({
                          ...base,
                          backgroundColor: state.isDisabled
                            ? "#f8f9fa"
                            : base.backgroundColor,
                          color: state.isDisabled ? "#6c757d" : base.color,
                          cursor: state.isDisabled ? "not-allowed" : "pointer",
                        }),
                      }}
                    />
                  </div>
                </div>

                <div className="col-12 mobile-centre-type-dropdown">
                  <div className="flx-between gap-1">
                    <label htmlFor="mobileCentreType" className="form-label font-16">
                      Healthcare Centre Type
                    </label>
                  </div>
                  <div className="position-relative">
                    <select
                      id="mobileCentreType"
                      className="common-input border-gray-five"
                      value={centreType}
                      onChange={(e) => {
                        setCentreType(e.target.value);
                        handleSearch(1);
                      }}
                    >
                      <option value="">All Healthcare Centres</option>
                      {centerStats?.map((centre, index) => (
                        <option key={index} value={centre.centreType}>
                          {centre.centreType}
                        </option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>
            </form>
          </div>

          <div className="col-xl-3 col-lg-4">
            {activeTab === "packages" && (
              <div className={`filter-sidebar ${filter ? "show" : ""}`}>
                <button
                  type="button"
                  className="filter-sidebar__close p-2 position-absolute end-0 top-0 z-index-1 text-body hover-text-main font-20 d-lg-none d-block"
                  onClick={handleFilter}
                >
                </button>

                <div className="filter-sidebar__item">
                  <button
                    type="button"
                    className="filter-sidebar__button font-16 text-capitalize fw-500"
                  >
                    Healthcare Centre Type
                  </button>

                  <div className="filter-sidebar__content">
                    <ul className="filter-sidebar-list">
                      <li className={`filter-sidebar-list__item`}>
                        <button
                          className={`filter-sidebar-list__text ${
                            centreType === "" ? "active-category" : ""
                          }`}
                          onClick={() => {
                            setCentreType("");
                            handleSearch(1);
                          }}
                        >
                          All Healthcare Centres
                        </button>
                      </li>
                      {centerStats?.map((centre, index) => (
                        <li key={index} className="filter-sidebar-list__item">
                          <button
                            className={`filter-sidebar-list__text ${
                              centreType === centre.centreType
                                ? "active-category"
                                : ""
                            }`}
                            onClick={(e) => {
                              e.preventDefault();
                              setCentreType(centre.centreType);
                              handleSearch(1);
                            }}
                          >
                            {centre.centreType}
                          </button>
                        </li>
                      ))}
                    </ul>
                  </div>
                </div>
              </div>
            )}
          </div>

          <div className="col-xl-9 col-lg-8">
            <div className="tab-content" id="pills-tabContent">
              <div
                className="tab-pane fade show active"
                id="pills-package"
                role="tabpanel"
                aria-labelledby="pills-package-tab"
                tabIndex={1}
              >
                <div className="row gy-4">
                  {loading ? (
                    <div className="col-12">
                      <div className="text-center py-5">
                        <div className="spinner-border text-primary" role="status">
                          <span className="visually-hidden">Loading packages...</span>
                        </div>
                        <p className="mt-2">Loading packages...</p>
                      </div>
                    </div>
                  ) : currentPackages.length > 0 ? (
                    currentPackages.map((doc, i) => (
                      <div className="col-xl-4 col-lg-4 col-sm-6" key={doc._id || i}>
                        <div
                          className="product-item h-90 d-flex flex-column overflow-hidden"
                          style={{ boxShadow: "0 0 10px rgba(0, 0, 0, 0.1)" }}
                        >
                          <div
                            className="product-item__thumb d-flex"
                            style={{ height: "180px" }}
                          >
                            <Link
                              to={`/package/${createSlug(doc.centre?.centreName)}/${createSlug(doc.packageName)}?id=${safeEncodeId(doc._id)}`}
                              className="link w-100"
                            >
                              <img
                                src={doc?.centre?.logo}
                                alt="Package"
                                style={{ height: "180px", objectFit: "fill" }}
                                className="cover-img"
                              />
                            </Link>
                          </div>

                          <div className="product-item__content d-flex flex-column p-3 flex-grow-1">
                            <h6 className="product-item__title">
                              <Link
                                to={`/package/${createSlug(doc.centre?.centreName)}/${createSlug(doc.packageName)}?id=${safeEncodeId(doc._id)}`}
                                className="link"
                              >
                                {toTitleCase(doc.packageName)}
                              </Link>
                            </h6>

                            <div className="product-item__info d-flex justify-content-between align-items-center">
                              <span
                                className="product-item__author text-muted small"
                                style={{
                                  display: "-webkit-box",
                                  WebkitLineClamp: 2,
                                  WebkitBoxOrient: "vertical",
                                  overflow: "hidden",
                                  textOverflow: "ellipsis",
                                  maxWidth: "60%",
                                  height: "2.9em",
                                }}
                              >
                                <Link
                                  to={`/${createSlug(doc?.centre?.centreName)}?location=${createSlug(doc?.centre?.city)}&locality=${createSlug(doc?.centre?.place)}&id=${safeEncodeId(doc?.centre?._id)}`}
                                  className="link hover-text-decoration-underline"
                                  style={{ textDecoration: "none" }}
                                >
                                  {toTitleCase(doc?.centre?.centreName)}
                                </Link>
                              </span>
                              <div className="d-flex align-items-center gap-1 flex-shrink-0">
                                <h6 className="product-item__price mb-0 text-success fw-bold">
                                  ₹{doc.totalPrice}
                                </h6>
                                {doc.discountPrice ? (
                                  <span className="product-item__prevPrice text-decoration-line-through">
                                    ₹{doc.actualPrice}
                                  </span>
                                ) : null}
                              </div>
                            </div>

                            <div className="product-item__info package-item__info flx-between gap-2">
                              <div className="product-item__author">
                                {doc.services?.slice(0, 2).map((srv, index) => (
                                  <p 
                                    key={srv._id || index} 
                                    className="mb-1"
                                    style={{
                                      display: "-webkit-box",
                                      WebkitLineClamp: 1,
                                      WebkitBoxOrient: "vertical",
                                      overflow: "hidden",
                                      textOverflow: "ellipsis",
                                    }}
                                  >
                                    {toTitleCase(srv.serviceName)}
                                  </p>
                                ))}
                                {doc.services?.length > 2 && (
                                  <Link
                                    to={`/package/${createSlug(doc.centre?.centreName)}/${createSlug(doc.packageName)}?id=${safeEncodeId(doc._id)}`}
                                    className="link hover-text-decoration-underline text-primary"
                                  >
                                    + {doc.services.length - 2} more
                                  </Link>
                                )}
                              </div>
                            </div>

                            <div
                              className="mt-auto d-flex gap-2"
                              style={{ borderTop: "none" }}
                            >
                              <Link
                                to={`/package/${createSlug(doc.centre?.centreName)}/${createSlug(doc.packageName)}?id=${safeEncodeId(doc._id)}`}
                                className="btn btn-outline-light btn-sm pill w-100"
                              >
                                More Details
                              </Link>

                              {/* <Link
                                to="/cart"
                                state={{ from: "/all-package" }}
                                className="btn btn-outline-light btn-sm pill w-100"
                                onClick={() => {
                                  // if (doc._id) {
                                  //   handleBookNowPackage(doc._id, "/all-package");
                                  // }
                                  if (hashids.encodeHex(doc?._id?.toString())) {
                                    handleBookNowPackage(hashids.encodeHex(doc?._id?.toString()), "/all-package");
                                  }
                                }}
                              >
                                Book Now
                              </Link> */}
                              <Link
  to="/cart"
  state={{ from: "/all-package" }}
  className="btn btn-outline-light btn-sm pill w-100"
  onClick={() => {
    // Pass the original ID, not the encoded one
    if (doc._id) {
      handleBookNowPackage(doc._id, "/all-package");
    }
  }}
>
  Book Now
</Link>
                            </div>
                          </div>
                        </div>
                      </div>
                    ))
                  ) : (
                    <div className="col-12 text-center py-5">
                      <h5 className="mt-3 text-muted">No Packages found</h5>
                      <p className="text-muted">Try adjusting your search or filters</p>
                      <button 
                        className="btn btn-main mt-2"
                        onClick={clearAllFilters}
                      >
                        Clear All Filters
                      </button>
                    </div>
                  )}
                </div>

                {currentPackages.length > 0 && totalPages > 1 && (
                  <nav aria-label="Page navigation example">
                    <ul className="pagination common-pagination justify-content-center">
                      {renderPagination()}
                    </ul>
                  </nav>
                )}
              </div>
            </div>
          </div>
        </div>
        <style>{`
          /* Show mobile dropdown only on screens less than 990px */
          .mobile-centre-type-dropdown {
            display: none;
          }

          @media (max-width: 989px) {
            .mobile-centre-type-dropdown {
              display: block;
            }
          }

          /* Hide desktop sidebar on screens less than 990px */
          @media (max-width: 989px) {
            .filter-sidebar {
              display: none !important;
            }
          }
        `}</style>
      </div>
    </section>
  );
};

export default AllHealthPackages;